    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0] addr;
    input [31:0] data;
    begin
      @(posedge clk);
      cs = 1; we = 1;
      address = addr;
      write_data = data;
      #20;
      cs = 0; we = 0;
    end
  endtask

  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
